import{_ as i,o as e,c as a,a2 as s}from"./chunks/framework.N6Nd-M9-.js";const c=JSON.parse('{"title":"💰 销售系统","description":"","frontmatter":{},"headers":[],"relativePath":"notes/企业文化/新人手册/04-销售系统.md","filePath":"notes/企业文化/新人手册/04-销售系统.md"}'),t={name:"notes/企业文化/新人手册/04-销售系统.md"};function r(p,d,l,o,x,n){return e(),a("div",null,[...d[0]||(d[0]=[s('<h1 id="💰-销售系统" tabindex="-1">💰 销售系统 <a class="header-anchor" href="#💰-销售系统" aria-label="Permalink to &quot;💰 销售系统&quot;">​</a></h1><blockquote><p>销售系统是公司的核心业务支撑，了解销售流程和方法，是你开展工作的基础。 💡 销售系统是公司将产品转化为价值的核心机制，包...</p></blockquote><hr><h2 id="💰-销售五步" tabindex="-1">💰 销售五步 <a class="header-anchor" href="#💰-销售五步" aria-label="Permalink to &quot;💰 销售五步&quot;">​</a></h2><div style="display:flex;flex-wrap:wrap;gap:12px;justify-content:center;"><div class="tc-center" style="flex:1;min-width:150px;max-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px 16px;"><div style="font-size:32px;margin-bottom:8px;">👋</div><div class="tc-blue tc-bold" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:50%;width:36px;height:36px;line-height:36px;margin:0 auto 10px;font-size:16px;">1</div><div class="tc-blue tc-bold" style="font-size:18px;margin-bottom:8px;">打招呼</div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:8px 12px;border-radius:8px;font-size:14px;">目光、笑容、热忱</div></div><div class="tc-center" style="flex:1;min-width:150px;max-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px 16px;"><div style="font-size:32px;margin-bottom:8px;">🤝</div><div class="tc-blue tc-bold" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:50%;width:36px;height:36px;line-height:36px;margin:0 auto 10px;font-size:16px;">2</div><div class="tc-blue tc-bold" style="font-size:18px;margin-bottom:8px;">介绍自己</div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:8px 12px;border-radius:8px;font-size:14px;">简单、清楚、自信</div></div><div class="tc-center" style="flex:1;min-width:150px;max-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px 16px;"><div style="font-size:32px;margin-bottom:8px;">📦</div><div class="tc-blue tc-bold" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:50%;width:36px;height:36px;line-height:36px;margin:0 auto 10px;font-size:16px;">3</div><div class="tc-blue tc-bold" style="font-size:18px;margin-bottom:8px;">介绍产品</div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:8px 12px;border-radius:8px;font-size:14px;">将产品放到客人手中、炒价格</div></div><div class="tc-center" style="flex:1;min-width:150px;max-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px 16px;"><div style="font-size:32px;margin-bottom:8px;">✅</div><div class="tc-blue tc-bold" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:50%;width:36px;height:36px;line-height:36px;margin:0 auto 10px;font-size:16px;">4</div><div class="tc-blue tc-bold" style="font-size:18px;margin-bottom:8px;">成交</div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:8px 12px;border-radius:8px;font-size:14px;">假设、问题、动作</div></div><div class="tc-center" style="flex:1;min-width:150px;max-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px 16px;"><div style="font-size:32px;margin-bottom:8px;">🚀</div><div class="tc-blue tc-bold" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:50%;width:36px;height:36px;line-height:36px;margin:0 auto 10px;font-size:16px;">5</div><div class="tc-blue tc-bold" style="font-size:18px;margin-bottom:8px;">再次成交</div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:8px 12px;border-radius:8px;font-size:14px;">创造需求、乘胜追击</div></div></div><br><h2 id="📌-成功八点" tabindex="-1">📌 成功八点 <a class="header-anchor" href="#📌-成功八点" aria-label="Permalink to &quot;📌 成功八点&quot;">​</a></h2><div style="display:flex;flex-wrap:wrap;gap:12px;"><div style="flex:1 1 calc(50% - 12px);min-width:250px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;"><div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;"><span style="font-size:24px;">😊</span><span class="tc-blue tc-bold tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:50%;width:30px;height:30px;line-height:30px;font-size:14px;">1</span><span class="tc-blue tc-bold" style="font-size:16px;">良好的态度</span></div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;font-size:14px;line-height:1.6;">用最好的态度、饱满的热情与冲动来与人沟通。</div></div><div style="flex:1 1 calc(50% - 12px);min-width:250px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;"><div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;"><span style="font-size:24px;">⏰</span><span class="tc-blue tc-bold tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:50%;width:30px;height:30px;line-height:30px;font-size:14px;">2</span><span class="tc-blue tc-bold" style="font-size:16px;">准时</span></div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;font-size:14px;line-height:1.6;">充分运用时间，创造最高效率。</div></div><div style="flex:1 1 calc(50% - 12px);min-width:250px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;"><div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;"><span style="font-size:24px;">📋</span><span class="tc-blue tc-bold tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:50%;width:30px;height:30px;line-height:30px;font-size:14px;">3</span><span class="tc-blue tc-bold" style="font-size:16px;">做好准备</span></div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;font-size:14px;line-height:1.6;">为完成每一个目标，预先筹备资源，计划成功。</div></div><div style="flex:1 1 calc(50% - 12px);min-width:250px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;"><div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;"><span style="font-size:24px;">💪</span><span class="tc-blue tc-bold tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:50%;width:30px;height:30px;line-height:30px;font-size:14px;">4</span><span class="tc-blue tc-bold" style="font-size:16px;">做足八小时</span></div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;font-size:14px;line-height:1.6;">尽心尽力尽意尽性去达成你的目标。</div></div><div style="flex:1 1 calc(50% - 12px);min-width:250px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;"><div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;"><span style="font-size:24px;">🗺️</span><span class="tc-blue tc-bold tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:50%;width:30px;height:30px;line-height:30px;font-size:14px;">5</span><span class="tc-blue tc-bold" style="font-size:16px;">保持地区</span></div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;font-size:14px;line-height:1.6;">彻底走遍你的地区与每一个顾客沟通，把握每一个机会。</div></div><div style="flex:1 1 calc(50% - 12px);min-width:250px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;"><div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;"><span style="font-size:24px;">🔥</span><span class="tc-blue tc-bold tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:50%;width:30px;height:30px;line-height:30px;font-size:14px;">6</span><span class="tc-blue tc-bold" style="font-size:16px;">保持态度</span></div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;font-size:14px;line-height:1.6;">时刻检讨你的态度，每一个&quot;NO&quot;会帮你接近下一个&quot;YES&quot;。</div></div><div style="flex:1 1 calc(50% - 12px);min-width:250px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;"><div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;"><span style="font-size:24px;">🎯</span><span class="tc-blue tc-bold tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:50%;width:30px;height:30px;line-height:30px;font-size:14px;">7</span><span class="tc-blue tc-bold" style="font-size:16px;">清楚自己做什么、为什么</span></div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;font-size:14px;line-height:1.6;">知道自己努力的方向及远景，推广产品固然重要，但用产品去学习这门生意就更重要。</div></div><div style="flex:1 1 calc(50% - 12px);min-width:250px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;"><div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;"><span style="font-size:24px;">🎭</span><span class="tc-blue tc-bold tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:50%;width:30px;height:30px;line-height:30px;font-size:14px;">8</span><span class="tc-blue tc-bold" style="font-size:16px;">控制场面</span></div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;font-size:14px;line-height:1.6;">察言观色、随机应变、主动出击…</div></div></div><br><h2 id="📌-平均法" tabindex="-1">📌 平均法 <a class="header-anchor" href="#📌-平均法" aria-label="Permalink to &quot;📌 平均法&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:24px;margin-bottom:16px;"><div style="display:flex;align-items:center;gap:10px;margin-bottom:12px;"><span style="font-size:28px;">📖</span><span class="tc-blue tc-bold" style="font-size:18px;">什么是平均法？</span></div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:16px;border-radius:8px;font-size:14px;line-height:1.8;"> 平均法这一核心概念是根植在这门生意的每一个发展阶段、每一个部门及每一个运作领域中的成功定律，因此学习这一核心概念及如何正确运用是非常重要的。平均法是数学中的机率概念，问的人越多，机会就越大。在销售部门，平均法意味着用兴奋、积极的态度去拜访150至200位以上的客户。争取到最少50至70位以上的客户听完五步，就会得到一个区间的成交率—大约是1/5到1/10的成交机率。平均法是公司系统多年来用实际的市场营销验证出来的定律，是具有可靠性及科学性的。 </div></div><div style="display:flex;flex-wrap:wrap;gap:12px;"><div style="flex:1 1 calc(50% - 12px);min-width:250px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;"><div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;"><span style="font-size:24px;">⏱️</span><span class="tc-blue tc-bold tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:50%;width:30px;height:30px;line-height:30px;font-size:14px;">1</span><span class="tc-blue tc-bold" style="font-size:16px;">做足八小时——充分利用时间</span></div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;font-size:14px;line-height:1.6;">每天要先做好充分的地区准备，合理的安排及运用地区并规划好运作时间，以期让你每天拜访客户的时间都能获得效益最大化。</div></div><div style="flex:1 1 calc(50% - 12px);min-width:250px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;"><div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;"><span style="font-size:24px;">📍</span><span class="tc-blue tc-bold tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:50%;width:30px;height:30px;line-height:30px;font-size:14px;">2</span><span class="tc-blue tc-bold" style="font-size:16px;">保持地区——不挑选地区</span></div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;font-size:14px;line-height:1.6;">不论是什么地区，都要用积极乐观的态度去面对——见门就进。充分把握地区中的每一个角落、最大化地增加见人的密度，有助于更快熟悉市场、统筹安排、节约时间、减少盲目性。如此，最能了解自己地区的人和他们所想要的，在同等的地区经营的时间可以更久。</div></div><div style="flex:1 1 calc(50% - 12px);min-width:250px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;"><div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;"><span style="font-size:24px;">👥</span><span class="tc-blue tc-bold tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:50%;width:30px;height:30px;line-height:30px;font-size:14px;">3</span><span class="tc-blue tc-bold" style="font-size:16px;">不挑选客户</span></div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;font-size:14px;line-height:1.6;">相信任何人都是潜在顾客，不论是什么人，都用热情兴奋的态度去面对，见人就打招呼。充分挖掘市场和顾客潜力的同时，展现个人的能力和风范。</div></div><div style="flex:1 1 calc(50% - 12px);min-width:250px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;"><div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;"><span style="font-size:24px;">💬</span><span class="tc-blue tc-bold tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:50%;width:30px;height:30px;line-height:30px;font-size:14px;">4</span><span class="tc-blue tc-bold" style="font-size:16px;">有质量的沟通——兴奋度和良好的态度</span></div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;font-size:14px;line-height:1.6;">兴奋的五步才能感染客户，良好的沟通才能有助成交。所以在业务中要保持好轻松、积极、乐观、兴奋的态度与足够多的客户做良好的沟通，才能得到平均法的效益。</div></div><div style="flex:1 1 calc(50% - 12px);min-width:250px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;"><div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;"><span style="font-size:24px;">⚡</span><span class="tc-blue tc-bold tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:50%;width:30px;height:30px;line-height:30px;font-size:14px;">5</span><span class="tc-blue tc-bold" style="font-size:16px;">HUSTLE——节奏快且有效率</span></div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;font-size:14px;line-height:1.6;">外出作业中，走路的速度要快、成交要快，不可磨客户。</div></div><div style="flex:1 1 calc(50% - 12px);min-width:250px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;"><div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;"><span style="font-size:24px;">📊</span><span class="tc-blue tc-bold tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:50%;width:30px;height:30px;line-height:30px;font-size:14px;">6</span><span class="tc-blue tc-bold" style="font-size:16px;">见足够多的客户</span></div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;font-size:14px;line-height:1.6;">做销售最大的问题就是客户少，抱怨多。没有结果说什么都是无济于事的，倒不如建设性检讨过自己。人数的量变，带来销售的质变。你拜访的客户越多，你成交的客户就越多。当然咱们指的拜访都是用心的拜访，认真去对待的拜访。记住，在外出作业的时候，不让他人浪费自己的时间，少聊天，多见顾客。</div></div></div><br><h2 id="💪-如何提升销售能力" tabindex="-1">💪 如何提升销售能力 <a class="header-anchor" href="#💪-如何提升销售能力" aria-label="Permalink to &quot;💪 如何提升销售能力&quot;">​</a></h2><div style="display:flex;flex-wrap:wrap;gap:12px;"><div class="tc-center" style="flex:1 1 calc(50% - 12px);min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:24px;"><div style="font-size:40px;margin-bottom:12px;">🧠</div><div class="tc-blue tc-bold" style="font-size:20px;margin-bottom:8px;">态度</div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;font-size:14px;">平头哥精神</div></div><div class="tc-center" style="flex:1 1 calc(50% - 12px);min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:24px;"><div style="font-size:40px;margin-bottom:12px;">👔</div><div class="tc-blue tc-bold" style="font-size:20px;margin-bottom:8px;">个人形象</div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;font-size:14px;">专业、整洁、得体</div></div><div class="tc-center" style="flex:1 1 calc(50% - 12px);min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:24px;"><div style="font-size:40px;margin-bottom:12px;">🎯</div><div class="tc-blue tc-bold" style="font-size:20px;margin-bottom:8px;">目标</div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;font-size:14px;">问足够多的人</div></div><div class="tc-center" style="flex:1 1 calc(50% - 12px);min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:24px;"><div style="font-size:40px;margin-bottom:12px;">🗣️</div><div class="tc-blue tc-bold" style="font-size:20px;margin-bottom:8px;">沟通质量</div><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;font-size:14px;">有效沟通、感染客户</div></div></div><br><h3 id="平头哥精神" tabindex="-1">平头哥精神 <a class="header-anchor" href="#平头哥精神" aria-label="Permalink to &quot;平头哥精神&quot;">​</a></h3><div style="display:flex;flex-wrap:wrap;gap:12px;justify-content:center;"><div class="tc-center" style="flex:1;min-width:180px;max-width:280px;background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.15);border-radius:12px;padding:30px 20px;"><div class="tc-red tc-bold" style="font-size:48px;margin-bottom:8px;">胆子<span style="color:#f97316;">大</span></div><div class="tc-body" style="font-size:14px;">敢于面对一切挑战</div></div><div class="tc-center" style="flex:1;min-width:180px;max-width:280px;background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.15);border-radius:12px;padding:30px 20px;"><div class="tc-red tc-bold" style="font-size:48px;margin-bottom:8px;">不怕<span style="color:#f97316;">事</span></div><div class="tc-body" style="font-size:14px;">勇往直前无所畏惧</div></div><div class="tc-center" style="flex:1;min-width:180px;max-width:280px;background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.15);border-radius:12px;padding:30px 20px;"><div class="tc-red tc-bold" style="font-size:48px;margin-bottom:8px;">不服<span style="color:#f97316;">输</span></div><div class="tc-body" style="font-size:14px;">永不放弃坚持到底</div></div></div><br><h2 id="📋-市场作业行为规范守则" tabindex="-1">📋 市场作业行为规范守则 <a class="header-anchor" href="#📋-市场作业行为规范守则" aria-label="Permalink to &quot;📋 市场作业行为规范守则&quot;">​</a></h2><div style="display:flex;flex-direction:column;gap:12px;"><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px 20px;"><div style="display:flex;align-items:flex-start;gap:12px;"><span class="tc-blue tc-bold tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:8px;min-width:32px;height:32px;line-height:32px;font-size:14px;">1</span><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;font-size:14px;line-height:1.6;">严格遵守国家法律和行政法规，遵守公司制定的相关规章制度。</div></div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px 20px;"><div style="display:flex;align-items:flex-start;gap:12px;"><span class="tc-blue tc-bold tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:8px;min-width:32px;height:32px;line-height:32px;font-size:14px;">2</span><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;font-size:14px;line-height:1.6;">应发扬公司企业文化，维护公司形象，树立良好个人形象，自觉维护公司权益和声誉。</div></div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px 20px;"><div style="display:flex;align-items:flex-start;gap:12px;"><span class="tc-blue tc-bold tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:8px;min-width:32px;height:32px;line-height:32px;font-size:14px;">3</span><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;font-size:14px;line-height:1.6;">在开展业务过程中，需如实详尽向商户介绍我司产品，不得夸大、隐瞒及对商户做不实承诺。</div></div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px 20px;"><div style="display:flex;align-items:flex-start;gap:12px;"><span class="tc-blue tc-bold tc-center" style="background:rgba(102,126,234,0.08);border:1px solid rgba(102,126,234,0.15);border-radius:8px;min-width:32px;height:32px;line-height:32px;font-size:14px;">4</span><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;font-size:14px;line-height:1.6;">在开展业务过程中，提高法律意识，选择合法合规的优质客户。</div></div></div><div style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);border-radius:12px;padding:16px 20px;"><div style="display:flex;align-items:flex-start;gap:12px;"><span class="tc-red tc-bold tc-center" style="background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.15);border-radius:8px;min-width:32px;height:32px;line-height:32px;font-size:14px;">5</span><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;font-size:14px;line-height:1.6;">不得在开展业务过程中，涉及政治、宗教迷信、不道德、或其他非商业性话题；不得在其他公司兼职。</div></div></div><div style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);border-radius:12px;padding:16px 20px;"><div style="display:flex;align-items:flex-start;gap:12px;"><span class="tc-red tc-bold tc-center" style="background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.15);border-radius:8px;min-width:32px;height:32px;line-height:32px;font-size:14px;">6</span><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;font-size:14px;line-height:1.6;">未经公司允许，不得擅自收取额外费用，不得作出不符合实际情况的口头或书面承诺，不得利用公司的业务关系，推广其他公司的产品和服务。</div></div></div><div style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);border-radius:12px;padding:16px 20px;"><div style="display:flex;align-items:flex-start;gap:12px;"><span class="tc-red tc-bold tc-center" style="background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.15);border-radius:8px;min-width:32px;height:32px;line-height:32px;font-size:14px;">7</span><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;font-size:14px;line-height:1.6;">不得散布未经公司认可的业务、政策、运营等方面的信息，或对公司发布的各类信息作失实的表达或宣传，不得借助任何未经公司授权、不真实、过期、或不再适用的、与推广产品无关、或者导致客户误解的奖状和评语等资讯和凭证。</div></div></div><div style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);border-radius:12px;padding:16px 20px;"><div style="display:flex;align-items:flex-start;gap:12px;"><span class="tc-red tc-bold tc-center" style="background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.15);border-radius:8px;min-width:32px;height:32px;line-height:32px;font-size:14px;">8</span><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;font-size:14px;line-height:1.6;">只可使用公司允许的文字、录音、资料、影像开展业务活动、公司内部的资料，不得转借、发售及赠送给他人。</div></div></div><div style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);border-radius:12px;padding:16px 20px;"><div style="display:flex;align-items:flex-start;gap:12px;"><span class="tc-red tc-bold tc-center" style="background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.15);border-radius:8px;min-width:32px;height:32px;line-height:32px;font-size:14px;">9</span><div class="tc-body" style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;font-size:14px;line-height:1.6;">其他监管机构、国家法律规定的禁止行为。</div></div></div></div>',21)])])}const g=i(t,[["render",r]]);export{c as __pageData,g as default};
